mapper.select:
SELECT fi.fleet_item_id,d.* FROM t_fleet_item fi LEFT JOIN t_driver d ON fi.item_id = d.driver_id WHERE fi.fleet_id = #{queryForm.fleetId} AND fi.item_type = #{queryForm.itemType}
AND (INSTR(d.driver_name,#{queryForm.keyWords}) or INSTR(d.telephone,#{queryForm.keyWords}) or INSTR(fi.create_user_name ,#{queryForm.keyWords}) )
ORDER BY fi.create_time DESC

SELECT fi.fleet_item_id,v.* FROM t_fleet_item fi LEFT JOIN t_vehicle v ON fi.item_id = v.vehicle_id WHERE fi.fleet_id = #{queryForm.fleetId} AND fi.item_type = #{queryForm.itemType}
AND (INSTR(v.vehicle_number,#{queryForm.keyWords}) or INSTR(v.owner,#{queryForm.keyWords}) or INSTR(fi.create_user_name ,#{queryForm.keyWords}) )
ORDER BY fi.create_time DESC
